    if (!page) { console.log('No page target'); process.exit(1); }

    const ws = new WebSocket(page.webSocketDebuggerUrl);
    let msgId = 0;
    const send = (method, params) => {
      const id = ++msgId;
      ws.send(JSON.stringify({id, method, params: params || {}}));
      return id;
    };
    let pendingActions = [];

    ws.on('open', () => {
      send('Runtime.enable');
      // First, press 'b' to exit drawing mode
      setTimeout(() => {
        console.log('Sending key b to exit drawing mode...');
        send('Input.dispatchKeyEvent', {
          type: 'keyDown',
          key: 'b',
          code: 'KeyB',
          windowsVirtualKeyCode: 66
        });
      }, 1000);
      // Then wait and click START TRAINING
      setTimeout(() => {
        send('Runtime.evaluate', {
          expression: `(() => {
            // Try pressing Escape to exit drawing mode too
            const evt = new KeyboardEvent('keydown', {key: 'b'});
            document.dispatchEvent(evt);
            // Now search for start training button
            const btns = document.querySelectorAll('button, [role="button"]');
            for (const b of btns) {
              const txt = (b.textContent || '').trim();
              if (txt.toUpperCase().includes('START') && txt.toUpperCase().includes('TRAIN')) {
                b.scrollIntoView({block: 'center'});
                b.click();
                return 'CLICKED: ' + txt;
              }
            }
            // Check all interactive elements
            const all = document.querySelectorAll('*');
            for (const e of all) {
              const txt = (e.textContent || '').trim();
              if (txt.toUpperCase().includes('START TRAINING') && e.children.length === 0) {
                e.click();
                return 'CLICKED (leaf): ' + txt;
              }
            }
            // Check style visibility
            for (const b of btns) {
              const txt = (b.textContent || '').trim();
              const style = window.getComputedStyle(b);
              if ((txt.includes('START') || txt.includes('TRAIN')) && style.display !== 'none' && style.visibility !== 'hidden') {
                b.click();
                return 'CLICKED (visible): ' + txt;
              }
            }
            return 'Not found. Buttons: ' + Array.from(document.querySelectorAll('button')).filter(b => b.offsetParent !== null).map(b => '[' + (b.textContent || '').trim().slice(0,30) + ']').join(', ');
          })()`,
          returnByValue: true
        });
      }, 2000);
      // Check URL after click
      setTimeout(() => {
        send('Runtime.evaluate', {
          expression: '(window.location.href)',
          returnByValue: true
        });
      }, 5000);
    });

    ws.on('message', data => {
      const msg = JSON.parse(data.toString());
      if (msg.id && msg.result) {
        const val = msg.result.result?.value;
        if (val) console.log(val);
        if (val && val.startsWith('http')) {
          ws.close();
          process.exit(0);
        }
      }
      // Also end after 8 seconds
      setTimeout(() => { ws.close(); process.exit(0); }, 8000);
    });
  });
});
